const { initDB, runFindOrCreate, User, AuditLog } = require('./index');

async function verify() {
  await initDB();

  console.log('Testing normal_user...');
  const user1 = await runFindOrCreate('normal_user');
  if (user1 instanceof Error) {
    console.error('Error creating normal_user:', user1.message);
  } else {
    console.log('Created normal_user successfully');
  }

  const userCount1 = await User.count({ where: { username: 'normal_user' } });
  const logCount1 = await AuditLog.count({ where: { username: 'normal_user' } });
  console.log(`User count: ${userCount1}, AuditLog count: ${logCount1}`);

  console.log('\nTesting error_user...');
  const result2 = await runFindOrCreate('error_user');
  if (result2 instanceof Error) {
    console.log('Caught expected error for error_user:', result2.message);
  } else {
    console.error('Expected error for error_user but got success');
  }

  const userCount2 = await User.count({ where: { username: 'error_user' } });
  const logCount2 = await AuditLog.count({ where: { username: 'error_user' } });
  console.log(`User count: ${userCount2}, AuditLog count: ${logCount2}`);

  if (userCount2 === 0 && logCount2 === 0) {
    console.log('\nVerification SUCCESS: No traces of error_user found.');
  } else {
    console.error('\nVerification FAILED: error_user or its AuditLog found in DB.');
    process.exit(1);
  }
}

verify().catch(err => {
  console.error('Verification script failed:', err);
  process.exit(1);
});

